args.sparql:
SELECT ?participant ?scoreLabel WHERE {
  wd:Q5033541 p:P710 ?statement.
  ?statement ps:P710 ?participant;
             pq:P1685 ?score.
  OPTIONAL { ?score rdfs:label ?scoreLabel FILTER(lang(?scoreLabel) = 'en') }
  SERVICE wikibase:label { bd:serviceParam wikibase:language 'en'. }
} LIMIT 10

SELECT ?participant ?score ?round WHERE {
  wd:Q5033541 p:P710 ?statement.
  ?statement ps:P710 ?participant.
  OPTIONAL { ?statement pq:P1351 ?score }
  OPTIONAL { ?statement pq:P1545 ?round }
}
LIMIT 10
